// ── CONFIG ───────────────────────────────────────────────────────────────────
const now = new Date();
const currentYear = now.getFullYear();
const currentMonth = now.getMonth() + 1;

// Weeks worked at CCI since April 10, 2026
const cciStartDate = new Date('2026-04-10');
const weeksWorkedCCI = Math.max(0, Math.floor((now - cciStartDate) / (7 * 24 * 60 * 60 * 1000)));

// Total CCI weeks in 2026 (Apr 10 to Dec 31)
const cciTotalWeeks = Math.floor((new Date('2026-12-31') - cciStartDate) / (7 * 24 * 60 * 60 * 1000));
const weeksRemaining = Math.max(0, cciTotalWeeks - weeksWorkedCCI);

// Last month label for report
const reportMonth = new Date(currentYear, currentMonth - 2, 1)
  .toLocaleDateString('en-US', { month: 'long', year: 'numeric' });

// ── PHASE DETECTION ──────────────────────────────────────────────────────────
// Phase 1: Apr 10 – Jun 9   (no 401k, no insurance)
// Phase 2: Jun 10 – Jul 10  (401k 4% starts)
// Phase 3: Jul 10+          (full deductions)
const phase2Start = new Date('2026-06-10');
const phase3Start = new Date('2026-07-10');
let activePhase = 1;
if (now >= phase3Start) activePhase = 3;
else if (now >= phase2Start) activePhase = 2;

// ── CCI WEEKLY AMOUNTS BY PHASE ──────────────────────────────────────────────
// Source: Pay stub Voucher 50608, April 10 2026
// Update Phase 2/3 amounts when first stub with new deductions arrives
const phases = {
  1: {
    // Net: $3,351.10 | Gross: $4,538.46 | No 401k, no insurance
    salary:         4423.08,
    vehicleAllow:    115.38,
    federalTax:      656.93,
    medicare:         65.81,
    michiganTax:     183.24,
    socialSecurity:  281.38,
    k401:              0.00,
    insurance:         0.00,
    hsa:               0.00,
  },
  2: {
    // UPDATE these from first stub showing 401k deduction (~June 10)
    // Est: 401k = 4% of $4,423.08 = $176.92, FITW drops slightly
    salary:         4423.08,
    vehicleAllow:    115.38,
    federalTax:      620.00,  // estimate — update from stub
    medicare:         65.81,
    michiganTax:     183.24,
    socialSecurity:  281.38,
    k401:            176.92,
    insurance:         0.00,
    hsa:               0.00,
  },
  3: {
    // UPDATE these from first full-deduction stub (~July 10)
    salary:         4423.08,
    vehicleAllow:    115.38,
    federalTax:      600.00,  // estimate — update from stub
    medicare:         65.81,
    michiganTax:     183.24,
    socialSecurity:  281.38,
    k401:            176.92,
    insurance:        115.00,  // estimate — update from stub
    hsa:              85.00,   // estimate — update from stub
  },
};

const weekly = phases[activePhase];

// ── CALCULATE CCI YTD ────────────────────────────────────────────────────────
// For phases with phase transitions, calculate weeks in each phase
let cciYTD;
if (activePhase === 1) {
  cciYTD = {
    salary:         weeksWorkedCCI * weekly.salary,
    vehicleAllow:   weeksWorkedCCI * weekly.vehicleAllow,
    federalTax:     weeksWorkedCCI * weekly.federalTax,
    medicare:       weeksWorkedCCI * weekly.medicare,
    michiganTax:    weeksWorkedCCI * weekly.michiganTax,
    socialSecurity: weeksWorkedCCI * weekly.socialSecurity,
    k401:           0,
    insurance:      0,
    hsa:            0,
  };
} else {
  // Approximate — more accurate after Phase 1 ends
  const weeksPhase1 = Math.floor((phase2Start - cciStartDate) / (7 * 24 * 60 * 60 * 1000));
  const weeksPhase2 = activePhase >= 3
    ? Math.floor((phase3Start - phase2Start) / (7 * 24 * 60 * 60 * 1000))
    : weeksWorkedCCI - weeksPhase1;
  const weeksPhase3 = activePhase >= 3 ? weeksWorkedCCI - weeksPhase1 - weeksPhase2 : 0;

  const p1 = phases[1];
  const p2 = phases[2];
  const p3 = phases[3];

  cciYTD = {
    salary:         weeksPhase1*p1.salary + weeksPhase2*p2.salary + weeksPhase3*p3.salary,
    vehicleAllow:   weeksPhase1*p1.vehicleAllow + weeksPhase2*p2.vehicleAllow + weeksPhase3*p3.vehicleAllow,
    federalTax:     weeksPhase1*p1.federalTax + weeksPhase2*p2.federalTax + weeksPhase3*p3.federalTax,
    medicare:       weeksPhase1*p1.medicare + weeksPhase2*p2.medicare + weeksPhase3*p3.medicare,
    michiganTax:    weeksPhase1*p1.michiganTax + weeksPhase2*p2.michiganTax + weeksPhase3*p3.michiganTax,
    socialSecurity: weeksPhase1*p1.socialSecurity + weeksPhase2*p2.socialSecurity + weeksPhase3*p3.socialSecurity,
    k401:           weeksPhase2*p2.k401 + weeksPhase3*p3.k401,
    insurance:      weeksPhase3*p3.insurance,
    hsa:            weeksPhase3*p3.hsa,
  };
}

// ── DMS YTD STATIC DATA (never changes) ──────────────────────────────────────
const dmsYTD = {
  grossEarnings:  47642.75,
  federalWH:       8373.45,
  michiganWH:      1839.27,
  socialSecurity:  2857.52,
  medicare:         668.29,
  detroitCityWH:    536.96,
  preTax401k:      1209.12,
  rothContrib:     1433.27,
  hsa:              975.00,
};

// ── COMBINED YTD ─────────────────────────────────────────────────────────────
const combinedYTD = {
  grossEarnings:  dmsYTD.grossEarnings + cciYTD.salary + cciYTD.vehicleAllow,
  federalWH:      dmsYTD.federalWH + cciYTD.federalTax,
  michiganWH:     dmsYTD.michiganWH + cciYTD.michiganTax,
  socialSecurity: dmsYTD.socialSecurity + cciYTD.socialSecurity,
  medicare:       dmsYTD.medicare + cciYTD.medicare,
  k401:           dmsYTD.preTax401k + cciYTD.k401,
  hsa:            dmsYTD.hsa + cciYTD.hsa,
};

// ── FULL YEAR PROJECTION ──────────────────────────────────────────────────────
// Project remaining CCI weeks using current phase weekly amounts
const cciProjected = {
  gross:          cciYTD.salary + cciYTD.vehicleAllow + weeksRemaining * (weekly.salary + weekly.vehicleAllow),
  federalWH:      cciYTD.federalTax + weeksRemaining * weekly.federalTax,
  michiganWH:     cciYTD.michiganTax + weeksRemaining * weekly.michiganTax,
  socialSecurity: cciYTD.socialSecurity + weeksRemaining * weekly.socialSecurity,
  medicare:       cciYTD.medicare + weeksRemaining * weekly.medicare,
};

const signOnBonus = 10000; // Gross — received ~May 10 2026

const koryProjected = {
  gross:      dmsYTD.grossEarnings + cciProjected.gross + signOnBonus,
  federalWH:  dmsYTD.federalWH + cciProjected.federalWH,
  michiganWH: dmsYTD.michiganWH + cciProjected.michiganWH,
};

// Beth estimates — update when real data available
const bethGross   = 135000;
const bethFedWH   = 22000;
const bethMiWH    =  5400;

const householdGross  = koryProjected.gross + bethGross;
const totalFederalWH  = koryProjected.federalWH + bethFedWH;
const totalMichiganWH = koryProjected.michiganWH + bethMiWH;

const prompt = `You are a tax projection assistant for Kory Gollan, a Michigan resident filing Married Filing Jointly (MFJ) in 2026.

Current date: ${now.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}
Report period: ${reportMonth}
Phase: ${activePhase} (${activePhase === 1 ? 'No 401k/insurance yet' : activePhase === 2 ? '401k started' : 'Full deductions'})
Weeks at CCI: ${weeksWorkedCCI} of ${cciTotalWeeks} total

## YTD ACTUAL (calculated from known weekly amounts)

DMS/Voltava (Jan 1 – Mar 31, 2026 — FINAL):
- Gross earnings: $${dmsYTD.grossEarnings.toFixed(2)}
- Federal withheld: $${dmsYTD.federalWH.toFixed(2)} (filed Single + $100 extra at DMS)
- Michigan withheld: $${dmsYTD.michiganWH.toFixed(2)}
- Social Security: $${dmsYTD.socialSecurity.toFixed(2)}
- Medicare: $${dmsYTD.medicare.toFixed(2)}
- Detroit City Tax: $${dmsYTD.detroitCityWH.toFixed(2)}
- Pre-tax 401k: $${dmsYTD.preTax401k.toFixed(2)}

CCI/Commerce Controls (${weeksWorkedCCI} weeks at $${weekly.salary}/wk base):
- Gross salary: $${cciYTD.salary.toFixed(2)}
- Vehicle allowance: $${cciYTD.vehicleAllow.toFixed(2)}
- Federal withheld: $${cciYTD.federalTax.toFixed(2)} (M + $50 extra/week)
- Michigan withheld: $${cciYTD.michiganTax.toFixed(2)}
- Social Security: $${cciYTD.socialSecurity.toFixed(2)}
- Medicare: $${cciYTD.medicare.toFixed(2)}
- 401k: $${cciYTD.k401.toFixed(2)}
- Sign-on bonus (gross): $10,000 received ~May 2026

Beth (estimate — actual data not yet available):
- Annual salary: ~$135,000
- Est. federal withheld: ~$22,000
- Est. Michigan withheld: ~$5,400

## FULL YEAR 2026 PROJECTION

Kory projected:
- Total gross: $${koryProjected.gross.toFixed(0)}
- Total federal withheld: $${koryProjected.federalWH.toFixed(0)}
- Total Michigan withheld: $${koryProjected.michiganWH.toFixed(0)}

Combined household:
- Total gross: $${householdGross.toFixed(0)}
- Total federal withheld: $${totalFederalWH.toFixed(0)}
- Total Michigan withheld: $${totalMichiganWH.toFixed(0)}

## NOTES
- Filing: MFJ
- Standard deduction 2026 (est.): ~$30,000
- SS wage base 2026: ~$176,100
- Detroit City Tax: $${dmsYTD.detroitCityWH.toFixed(2)} already withheld — DMS only, no city tax at CCI (Novi)
- CCI W-4: M + $50 extra/week — may be insufficient
- Kory Q1 2027 bonus (~$92k gross) NOT included — may fall in tax year 2027

Provide:
1. Estimated 2026 federal tax liability (use 2025 MFJ brackets adjusted for inflation)
2. Projected federal over/underpayment
3. Michigan state tax liability and over/underpayment
4. SS wage base analysis
5. Specific W-4 recommendation: additional weekly withholding to close gap by Dec 31
6. Key flags for CPA

Be direct and specific. Dollar amounts. Note Beth data is estimated. Under 350 words.`;

return [{
