    telegramBotToken: '8634364235:AAF1NgjnXdkFvcuv4uxZF36xtM9ySunrtLA',
    telegramChatId: '7652111268',
    reportMonth,
    activePhase,
    weeksWorkedCCI,
    dmsYTD,
    cciYTD,
    combinedYTD,
    koryProjected,
