msg += 'Total MI WH:      $' + totalMichiganWH.toFixed(0) + '\n\n';

msg += '--- CLAUDE ANALYSIS ---\n';
msg += analysis;

msg += '\n\nPaycheck ref: notion.so/341a962387d18163bd4fc4c7b9cbdf55';

